import pickle
from flask import Flask, jsonify, request
from sklearn.linear_model import LogisticRegression
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.model_selection import train_test_split
import pandas as pd

app = Flask(__name__)

# Load the trained model
with open('model.pkl', 'rb') as file:
    model = pickle.load(file)

vectorizer = CountVectorizer()

def preprocess_text(text):
    return [word.lower() for word in text.split() if word.isalnum()]

@app.route('/predict', methods=['POST'])
def predict():
    data = request.json['data']
    text = ' '.join(preprocess_text(data))
    X = vectorizer.transform([text])
    prediction = model.predict(X)
    probability = model.predict_proba(X)[0][1]
    return jsonify({'spam': prediction, 'probability': probability})

if __name__ == "__main__":
    # Load data and train the model (You may need to preprocess your data before training)
    df = pd.read_csv('emails.csv')  # Assuming you have a CSV file with two columns: 'email' and 'spam'
    emails = df['email'].tolist()
    spam = df['spam'].astype(int).tolist()

    X_train, X_test, y_train, y_test = train_test_split(emails, spam, test_size=0.2)

    vectorizer = CountVectorizer()
    X_train = vectorizer.fit_transform(X_train)
    model = LogisticRegression()
    model.fit(X_train, y_train)

    # Save the trained model
    with open('model.pkl', 'wb') as file:
        pickle.dump(model, file)

    app.run(port=5000, debug=True)